import{_ as e,c as t,o as r,a1 as o}from"./chunks/framework.DILC4Csi.js";const f=JSON.parse('{"title":"FAQ: 故障排查 | opencode-md-table-formatter","description":"學習 opencode-md-table-formatter 外掛的常見問題和故障排查方法。快速定位表格格式化問題，解決設定、結構、對齊等疑難雜症。","frontmatter":{"title":"FAQ: 故障排查 | opencode-md-table-formatter","sidebarTitle":"遇到問題怎麼辦","subtitle":"FAQ: 故障排查 | opencode-md-table-formatter","description":"學習 opencode-md-table-formatter 外掛的常見問題和故障排查方法。快速定位表格格式化問題，解決設定、結構、對齊等疑難雜症。","order":3},"headers":[],"relativePath":"zh-tw/franlol/opencode-md-table-formatter/faq/index.md","filePath":"zh-tw/franlol/opencode-md-table-formatter/faq/index.md"}'),l={name:"zh-tw/franlol/opencode-md-table-formatter/faq/index.md"};function i(n,a,d,s,h,c){return r(),t("div",null,[...a[0]||(a[0]=[o('<h1 id="常見問題" tabindex="-1">常見問題 <a class="header-anchor" href="#常見問題" aria-label="Permalink to &quot;常見問題&quot;">​</a></h1><h2 id="章節概述" tabindex="-1">章節概述 <a class="header-anchor" href="#章節概述" aria-label="Permalink to &quot;章節概述&quot;">​</a></h2><p>本章節涵蓋 opencode-md-table-formatter 外掛的常見問題和故障排查方法，幫助你快速定位和解決表格格式化過程中遇到的各種問題。</p><hr><h2 id="子頁面導覽" tabindex="-1">子頁面導覽 <a class="header-anchor" href="#子頁面導覽" aria-label="Permalink to &quot;子頁面導覽&quot;">​</a></h2><h3 id="常見問題-表格沒格式化怎麼辦" tabindex="-1"><a href="./troubleshooting/">常見問題：表格沒格式化怎麼辦</a> <a class="header-anchor" href="#常見問題-表格沒格式化怎麼辦" aria-label="Permalink to &quot;[常見問題：表格沒格式化怎麼辦](troubleshooting/)&quot;">​</a></h3><p>全面介紹外掛使用中的常見問題和解決方案：</p><ul><li><strong>表格不格式化</strong>：檢查設定、版本要求、重新啟動 OpenCode</li><li><strong>無效表格結構</strong>：理解 &quot;invalid structure&quot; 錯誤含義，學習正確表格語法</li><li><strong>格式化失敗</strong>：處理 &quot;table formatting failed&quot; 錯誤和異常情況</li><li><strong>不支援的表格類型</strong>：了解 HTML 表格、多行儲存格等限制場景</li><li><strong>格式化後不對齊</strong>：排查隱藏模式、儲存格超長、行內代碼等問題</li></ul><hr><h2 id="學習路徑建議" tabindex="-1">學習路徑建議 <a class="header-anchor" href="#學習路徑建議" aria-label="Permalink to &quot;學習路徑建議&quot;">​</a></h2><p>建議在完成 <a href="./../start/features/">功能全覽</a> 後，遇到實際問題時查閱本章節，或作為問題排查的參考手冊。</p><p>你可以按照以下順序學習：</p><ol><li><strong>遇到問題時</strong>：先根據症狀定位問題類型（表格不格式化、報錯資訊等）</li><li><strong>按步驟排查</strong>：按照故障排查指南的檢查清單逐一驗證</li><li><strong>深入理解</strong>：閱讀<a href="./../advanced/table-spec/">表格規範</a>和<a href="./../advanced/concealment-mode/">隱藏模式原理</a>了解技術細節</li><li><strong>已知限制</strong>：查看<a href="./../appendix/limitations/">已知限制</a>了解外掛邊界</li></ol><hr><h2 id="前置條件" tabindex="-1">前置條件 <a class="header-anchor" href="#前置條件" aria-label="Permalink to &quot;前置條件&quot;">​</a></h2><p>學習本章節前，建議先完成：</p><ul><li>✅ <a href="./../start/getting-started/">一分鐘上手：安裝與設定</a> - 了解如何安裝和設定外掛</li><li>✅ <a href="./../start/features/">功能全覽：自動格式化的魔法</a> - 理解外掛的核心功能和工作原理</li></ul><p>同時，你應該具備：</p><ul><li>熟悉 Markdown 表格的基本語法</li><li>了解 OpenCode 的外掛設定方式（<code>opencode.jsonc</code>）</li></ul><hr><h2 id="下一步指引" tabindex="-1">下一步指引 <a class="header-anchor" href="#下一步指引" aria-label="Permalink to &quot;下一步指引&quot;">​</a></h2><p>完成本章節後，你可以繼續學習：</p><ul><li><p><strong>進階知識</strong>：</p><ul><li><a href="./../advanced/table-spec/">表格規範：什麼樣的表格能被格式化</a> - 掌握有效表格的結構要求</li><li><a href="./../advanced/concealment-mode/">隱藏模式原理：為什麼寬度計算如此重要</a> - 理解 OpenCode 隱藏模式的工作原理</li><li><a href="./../advanced/alignment/">對齊方式詳解：左對齊、置中、右對齊</a> - 掌握三種對齊方式的語法和效果</li></ul></li><li><p><strong>技術細節</strong>：</p><ul><li><a href="./../appendix/limitations/">已知限制：外掛的邊界在哪裡</a> - 了解外掛的已知限制和不適用的場景</li><li><a href="./../appendix/tech-details/">技術細節：快取機制與效能優化</a> - 了解外掛的內部快取機制和效能優化策略</li></ul></li></ul><hr>',24)])])}const m=e(l,[["render",i]]);export{f as __pageData,m as default};
